// =====================================================================
// NOMAAD Camp · Workflow 1 · Decompose into Quote Items (FULL)
// =====================================================================
// Output: All line items including camp-specific base zone items +
//         tier inclusions + billable addons + shuttle
// =====================================================================

const p = $('Code · Build metadata').first().json;
const quoteNum = p.quote_number;
const guests   = Number(p.guest_count) || 0;
const tier     = p.package_tier || '';
const items    = [];
let rowNum = 1;

const CAMP_BASE = {
  'NOMAAD Summit': {
    asar:     '540 м² үндсэн асар (өргөтгөл 1,500 м² хүртэл)',
    stage:    'Тайз каркас 8×4 м (32 м²)',
    sound:    'Хөгжмийн систем 16,000W',
    wc_count: 8,
    smoking_count: 3
  },
  'NOMAAD Meadow': {
    asar:     '300 м² үндсэн асар',
    stage:    'Тайз каркас 6×4 м (24 м²)',
    sound:    'Хөгжмийн систем 5,000W',
    wc_count: 6,
    smoking_count: 2
  },
  'NOMAAD Grove': {
    asar:     '200 м² үндсэн асар',
    stage:    'Тайз каркас 4×3 м (12 м²)',
    sound:    'Хөгжмийн систем 5,000W',
    wc_count: 4,
    smoking_count: 2
  }
};

const PRICES_FLAT = {
  moonbeam_lounge: 500000, led_screen_18m2: 1728000, open_mic: 500000,
  asar_decor: 2000000, extra_tents: 1300000, extra_lighting: 5000000,
  team_games: 1000000, program_consulting: 1000000, event_director: 1800000,
  medical_support: 1200000, security_service: 1500000,
  after_movie: 1000000, yoga: 1300000, canvas_art: 1500000
};

const UNIT_OVERRIDES = {
  asar_decor:         'багц',
  extra_tents:        'багц',
  extra_lighting:     'багц',
  team_games:         'багц',
  program_consulting: 'багц',
  event_director:     'багц',
  security_service:   'алба',
  yoga:               'багш',
  canvas_art:         'багш',
  medical_support:    'байршил',
  open_mic:           'багц',
  moonbeam_lounge:    'байршил',
  led_screen_18m2:    'ширхэг',
  after_movie:        'after movie'
};

const CATEGORY_MAP = {
  welcome_drink:      'Хоол, ресторан',
  sleeping_bag:       'Кемп',
  coffee_corner:      'Хоол, ресторан',
  lunch_upgrade:      'Хоол, ресторан',
  dinner_upgrade:     'Хоол, ресторан',
  moonbeam_lounge:    'Хоол, ресторан',
  bartender_service:  'Хоол, ресторан',
  late_snacks:        'Хоол, ресторан',
  dj_service:         'Энтертайнмент',
  led_screen_18m2:    'Энтертайнмент',
  open_mic:           'Энтертайнмент',
  asar_decor:         'Хоол, ресторан',
  extra_tents:        'Амралт',
  extra_lighting:     'Энтертайнмент',
  team_games:         'Спорт',
  program_consulting: 'Энтертайнмент',
  event_director:     'Энтертайнмент',
  medical_support:    'Ариун цэвэр',
  security_service:   'Ариун цэвэр',
  yoga:               'Спорт',
  canvas_art:         'Энтертайнмент',
  after_movie:        'Энтертайнмент'
};

function pushRow(category, name, qty, unit, unitPrice, total, included, note) {
  items.push({
    quote_id: quoteNum, row_num: rowNum++, category: category,
    name: name, qty: qty, unit: unit,
    unit_price: unitPrice || 0, total: total || 0,
    included: included ? 'Тийм' : 'Үгүй', note: note || ''
  });
}

const camp = CAMP_BASE[p.camp_name] || CAMP_BASE['NOMAAD Meadow'];

// Parse addons
let addons = [];
try { addons = JSON.parse(p.addons_json || '[]'); } catch (_) { addons = []; }
const includedCodes = new Set(addons.filter(a => a.tier_included).map(a => a.code));
const skipLunch  = includedCodes.has('lunch_upgrade');
const skipDinner = includedCodes.has('dinner_upgrade');

// ── 1. Tier base lump sum ──
pushRow('Үндсэн багц', `${p.camp_name} · ${tier}`, guests, 'хүн',
  Number(p.tier_base_price), Number(p.tier_subtotal), false, 'Багцын суурь үнэ');

// ── 2. Camp-specific base zone items (no unit price — included) ──
pushRow('Хоол, ресторан', camp.asar, 1, 'ширхэг', 0, 0, true, '');
pushRow('Хоол, ресторан', 'Ширээ сандал', guests, 'хүн', 0, 0, true, '');
pushRow('Хоол, ресторан', 'Асарын энгийн тохижилт', 1, 'багц', 0, 0, true, '');
pushRow('Хоол, ресторан', 'Өглөөний цай', guests, 'порц', 0, 0, true, '');
if (!skipLunch)  pushRow('Хоол, ресторан', 'Өдрийн хоол', guests, 'порц', 0, 0, true, '');
if (!skipDinner) pushRow('Хоол, ресторан', 'Оройн хоол',  guests, 'порц', 0, 0, true, '');

pushRow('Энтертайнмент', camp.stage, 1, 'ширхэг', 0, 0, true, '');
pushRow('Энтертайнмент', camp.sound, 1, 'багц',   0, 0, true, '');
pushRow('Энтертайнмент', 'Микрофон',  2, 'ширхэг', 0, 0, true, '');
pushRow('Энтертайнмент', 'Сүүдрэвч',  4, 'ширхэг', 0, 0, true, '');

pushRow('Амралт', '3×6 м асар',        1, 'ширхэг', 0, 0, true, '');
pushRow('Амралт', 'Түүдэг галын хэсэг', 1, 'ширхэг', 0, 0, true, '');
pushRow('Амралт', 'Дүүжин ор', 15, 'ширхэг', 0, 0, true, '');

pushRow('Спорт', 'Гар бөмбөг, хөлбөмбөг, cornhole, олс таталт', 1, 'багц', 0, 0, true, '');

pushRow('Ариун цэвэр', 'Ариун цэврийн өрөө', camp.wc_count, 'ширхэг', 0, 0, true, '');
pushRow('Ариун цэвэр', 'Тамхины цэг', camp.smoking_count, 'байршил', 0, 0, true, '');

pushRow('Кемп', 'Майхан 6 хүний', Math.ceil(guests/6) || 1, 'ширхэг', 0, 0, true, '');

// ── 3. Tier inclusion addons (Стандарт/Премиум-аас ирсэн) ──
for (const a of addons) {
  if (!a.tier_included) continue;
  if (a.code === 'coffee_corner') {
    pushRow('Хоол, ресторан', 'Sunrise Coffee Corner', 1, 'байршил', 0, 0, true, '07:30–09:00');
    continue;
  }
  let qty, unit, total;
  if (a.code === 'bartender_service') {
    qty = a.bartender_count || Math.ceil(guests/75) || 1;
    unit = 'ажилтан'; total = 0;
  } else if (a.code === 'late_snacks') {
    qty = a.quantity || (tier === 'Премиум' ? 5 : Math.ceil(guests/15) || 1);
    unit = 'platter'; total = 0;
  } else if (a.code === 'dj_service') {
    qty = 1; unit = '3 цаг'; total = 0;
  } else if (a.type === 'per-person') {
    qty = a.quantity || guests; unit = 'хүн'; total = 0;
  } else {
    qty = 1; unit = UNIT_OVERRIDES[a.code] || 'ширхэг'; total = 0;
  }
  const cat3 = CATEGORY_MAP[a.code] || 'Багцад орсон';
  pushRow(cat3, a.name, qty, unit, 0, 0, true, '');
}

// ── 4. Billable (customer-added) addons ──
for (const a of addons) {
  if (a.tier_included) continue;
  if (a.code === 'coffee_corner') continue;

  let qty, unit, unitPrice, total;
  if (a.code === 'bartender_service') {
    qty = a.bartender_count || Math.ceil(guests/75) || 1;
    unit = 'ажилтан'; unitPrice = 500000; total = qty * unitPrice;
  } else if (a.code === 'late_snacks') {
    qty = a.quantity || Math.ceil(guests/15) || 1;
    unit = 'platter'; unitPrice = 250000; total = qty * unitPrice;
  } else if (a.code === 'dj_service') {
    qty = 1; unit = a.duration ? (a.duration + ' цаг') : '3 цаг';
    unitPrice = a.price || 1000000; total = unitPrice;
  } else if (a.type === 'per-person') {
    qty = a.quantity || guests; unit = 'хүн';
    unitPrice = a.unit_price || 0; total = qty * unitPrice;
  } else {
    qty = 1; unit = UNIT_OVERRIDES[a.code] || 'ширхэг';
    unitPrice = a.price || PRICES_FLAT[a.code] || 0; total = unitPrice;
  }
  const cat4 = CATEGORY_MAP[a.code] || 'Нэмэлт';
  pushRow(cat4, a.name, qty, unit, unitPrice, total, false, '');
}

// ── 5. Shuttle ──
const shuttleSubtotal = Number(p.shuttle_subtotal) || 0;
if (shuttleSubtotal > 0) {
  pushRow('Тээвэр', p.shuttle_service || 'Тээврийн үйлчилгээ',
    Number(p.bus_count) || 1, 'автобус',
    Number(p.shuttle_unit_price), shuttleSubtotal, false, '');
}

return items.map(i => ({ json: i }));

// Capture quote metadata — Render HTML-ийн оронд жижиг helper
// Зөвхөн Sheet-д хадгалах, Gmail subject-д хэрэгтэй талбаруудыг бэлдэнэ.
// PDF биш — энэ нь Send workflow-н ажил.

const body = $('Webhook').first().json.body || {};
const counter = $('Sheets · Read counter').first().json;

// Counter Sheet-ээс өнөөгийн утгыг авна
const currentCounter = parseInt(counter['Тоолуур'] || counter['counter'] || counter['next'] || 0, 10) || 0;
const nextCounter = currentCounter + 1;
const year = new Date().getFullYear();
const quoteNumber = 'NC-' + year + '-' + String(nextCounter).padStart(4, '0');

// Addons summary string бэлдэх
let addonsSummary = '';
try {
  const addons = JSON.parse(body.addons_json || '[]');
  if (Array.isArray(addons) && addons.length) {
    addonsSummary = addons.map(a => `${a.name || a.label || ''}×${a.qty || 1}`).join(', ');
  }
} catch(e) { addonsSummary = ''; }

// Shuttle summary
const shuttleLabel = body.shuttle_service_label || body.shuttle_service || 'Сонгохгүй';
const busCount = body.bus_count || 1;
const shuttleSummary = shuttleLabel === 'Сонгохгүй' ? 'Тээвэр сонгоогүй' : `${shuttleLabel} · ${busCount} автобус`;

// Internal email subject
const emailSubjectInternal = `🆕 Шинэ үнийн санал ${quoteNumber} · ${body.company || body.contact_name || 'Үл мэдэгдэх'} · ${Number(body.grand_total || 0).toLocaleString('mn-MN')}₮`;

// Internal email body (HTML, гэхдээ маш богино — quote info-г нийлүүлж бэлдэх)
const emailBodyInternal = `<!DOCTYPE html><html><body style="font-family:Helvetica,Arial,sans-serif;background:#F5F1E8;padding:24px;">
<table cellpadding="0" cellspacing="0" width="600" align="center" style="background:#fff;border-radius:8px;padding:28px 24px;border-top:3px solid #2E3A28;">
<tr><td>
<p style="font-size:11px;color:#C8A878;letter-spacing:2px;margin:0 0 4px;">NOMAAD CAMP · INTERNAL</p>
<h2 style="font-size:18px;color:#1F2A23;margin:0 0 16px;">🆕 Шинэ үнийн санал ${quoteNumber}</h2>
<p style="font-size:13px;color:#5F5E5A;margin:0 0 16px;">Шинэ зочин квот авах хүсэлт илгээсэн байна. Доорх мэдээллийг шалгаад зочны email хайрцаг руу <strong>Send</strong> workflow-аар явуулна уу.</p>
<table cellpadding="6" cellspacing="0" width="100%" style="background:#F5F1E8;border-radius:6px;border-left:3px solid #C8A878;font-size:13px;color:#3D3C39;">
<tr><td width="40%"><strong>Компани</strong></td><td>${body.company || '—'}</td></tr>
<tr><td><strong>Холбоо барих</strong></td><td>${body.contact_name || '—'}</td></tr>
<tr><td><strong>Утас</strong></td><td>${body.phone || '—'}</td></tr>
<tr><td><strong>И-мэйл</strong></td><td>${body.email || '—'}</td></tr>
<tr><td><strong>Кемп</strong></td><td>${body.camp_name || '—'} · ${body.package_tier || '—'}</td></tr>
<tr><td><strong>Огноо</strong></td><td>${body.start_datetime || '—'} → ${body.end_datetime || '—'}</td></tr>
<tr><td><strong>Хүний тоо</strong></td><td>${body.guest_count || '—'}</td></tr>
<tr><td><strong>Нийт дүн</strong></td><td><strong>${Number(body.grand_total || 0).toLocaleString('mn-MN')}₮</strong></td></tr>
<tr><td><strong>Урьдчилгаа 30%</strong></td><td>${Number(body.deposit_30 || 0).toLocaleString('mn-MN')}₮</td></tr>
${addonsSummary ? `<tr><td><strong>Нэмэлт</strong></td><td>${addonsSummary}</td></tr>` : ''}
${body.notes ? `<tr><td><strong>Тэмдэглэл</strong></td><td>${body.notes}</td></tr>` : ''}
</table>
<p style="font-size:11px;color:#9A9A95;margin:18px 0 0;">Source: ${body.source || 'nomaadcamp.com'} · Огноо: ${new Date().toLocaleString('mn-MN')}</p>
</td></tr></table></body></html>`;

return [{ json: {
  ...body,
  quote_number: quoteNumber,
  next_counter_value: nextCounter,
  addons_summary: addonsSummary,
  shuttle_summary: shuttleSummary,
  email_subject_internal: emailSubjectInternal,
  email_body_internal: emailBodyInternal,
  original_payload: body,
} }];
